// ==================== Drop Overlay 组件 ====================

class DropOverlay {
    private elem: HTMLElement;

    constructor() {
        this.elem = document.createElement('div');
        this.elem.className = 'gotty-drop-overlay';
        this.elem.innerHTML = `
            <div class="gotty-drop-content">
                <div class="drop-icon">📁</div>
                <div class="drop-text">Drop files here to upload</div>
                <div class="file-list"></div>
                <div class="drop-hint">Release to upload</div>
            </div>
        `;
        document.body.appendChild(this.elem);
    }

    show(files: FileList | null) {
        const fileList = this.elem.querySelector('.file-list') as HTMLElement;
        if (files && files.length > 0) {
            fileList.innerHTML = Array.from(files)
                .map(f => `<div class="file-item"><span class="file-name">${this.escapeHtml(f.name)}</span> (${this.formatSize(f.size)})</div>`)
                .join('');
        } else {
            fileList.innerHTML = '';
        }
        this.elem.classList.add('active');
    }

    hide() {
        this.elem.classList.remove('active');
    }

    private formatSize(bytes: number): string {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
    }

    private escapeHtml(text: string): string {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    destroy() {
        document.body.removeChild(this.elem);
    }
}

// ==================== Upload Progress Modal 组件 ====================

interface UploadProgressModalProps {
    task: UploadTask;
    onCancel: () => void;
    onDismiss: () => void;
}

interface UploadProgressModalState {
    show: boolean;
    progress: number;
    speed: string;
    remaining: string;
    transferred: string;
    status: string;
}

class UploadProgressModal extends Component<UploadProgressModalProps, UploadProgressModalState> {
    private modalRef = createRef<HTMLDivElement>();
    private modalInstance: Modal | null = null;
    private updateTimer: NodeJS.Timeout | null = null;
    private hideListener: (() => void) | null = null;

    constructor(props: UploadProgressModalProps) {
        super(props);
        this.state = {
            show: true,
            progress: 0,
            speed: '0 B/s',
            remaining: '--',
            transferred: '0 B',
            status: 'uploading'
        };
    }

    componentDidMount() {
        this.modalInstance = Modal.getOrCreateInstance(this.modalRef.current!);
        this.modalInstance.show();

        // 监听关闭事件
        this.hideListener = () => this.props.onDismiss();
        this.modalRef.current?.addEventListener('hidden.bs.modal', this.hideListener);

        // 定时更新状态
        this.updateTimer = setInterval(() => this.updateState(), 200);
    }

    componentWillUnmount() {
        if (this.updateTimer) {
            clearInterval(this.updateTimer);
        }
        if (this.hideListener && this.modalRef.current) {
            this.modalRef.current.removeEventListener('hidden.bs.modal', this.hideListener);
        }
        this.modalInstance?.dispose();
    }

    static getDerivedStateFromProps(props: UploadProgressModalProps, state: UploadProgressModalState) {
        const newState = { ...state };

        if (props.task.status === 'completed') {
            newState.progress = 100;
            newState.speed = 'Done';
            newState.remaining = '';
            newState.status = 'completed';
        } else if (props.task.status === 'cancelled') {
            newState.status = 'cancelled';
        } else if (props.task.status === 'error') {
            newState.status = 'error';
        } else {
            newState.progress = props.task.progress;
            newState.speed = UploadProgressModal.formatSpeed(props.task.speed);

            const elapsed = Date.now() - props.task.startTime;
            if (elapsed > 1000 && props.task.progress > 0) {
                const totalTime = elapsed / (props.task.progress / 100);
                const remaining = Math.ceil((totalTime - elapsed) / 1000);
                newState.remaining = remaining > 60
                    ? `${Math.ceil(remaining / 60)} min`
                    : `${remaining} sec`;
            } else {
                newState.remaining = 'Calculating...';
            }

            newState.transferred = UploadProgressModal.formatSize(
                Math.floor((props.task.size * props.task.progress) / 100)
            );
        }

        return newState;
    }

    private updateState() {
        // 状态已在 getDerivedStateFromProps 中更新
        this.forceUpdate();
    }

    private handleCancel = () => {
        this.props.onCancel();
        // 不直接隐藏，让状态变化触发完成界面显示
    };

    private handleDismiss = () => {
        this.modalInstance?.hide();
        this.props.onDismiss();
    };

    render() {
        const { task } = this.props;
        const { progress, speed, remaining, transferred, status } = this.state;

        const progressBarClass = status === 'error' ? 'bg-danger' :
            status === 'cancelled' ? 'bg-warning' : 'bg-primary';
        const progressText = status === 'completed' ? 'Upload complete' :
            status === 'cancelled' ? 'Cancelled' :
                status === 'error' ? 'Upload failed' : '';

        return (
            <div class="modal fade gotty-upload-modal" ref={this.modalRef} tabIndex={-1}>
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Upload file</h5>
                            {status === 'uploading' && (
                                <button type="button" class="btn-close" onClick={this.handleDismiss}></button>
                            )}
                        </div>
                        <div class="modal-body">
                            {status === 'uploading' ? (
                                <div class="upload-progress">
                                    <div class="mb-2">
                                        <strong>{task.name}</strong>
                                        <span class="text-muted ms-2">({UploadProgressModal.formatSize(task.size)})</span>
                                    </div>

                                    <div class="progress">
                                        <div
                                            class={`progress-bar ${progressBarClass}`}
                                            role="progressbar"
                                            style={{ width: `${progress}%` }}
                                            aria-valuenow={progress}
                                            aria-valuemin={0}
                                            aria-valuemax={100}
                                        >
                                            {progress}%
                                        </div>
                                    </div>

                                    <div class="upload-stats">
                                        <span class="upload-speed">{speed}</span>
                                        <span class="upload-remaining">Remaining {remaining}</span>
                                    </div>

                                    <div class="text-center mt-2 text-muted" style={{ fontSize: '12px' }}>
                                        Transferred: {transferred}
                                    </div>
                                </div>
                            ) : (
                                <div class="upload-complete">
                                    {status === 'completed' && <div class="success-icon">✓</div>}
                                    {status === 'cancelled' && <div class="text-warning" style={{ fontSize: '48px' }}>✕</div>}
                                    {status === 'error' && <div class="text-danger" style={{ fontSize: '48px' }}>✕</div>}
                                    <div class="upload-filename">{task.name}</div>
                                    <div class="text-muted mt-2">{progressText}</div>
                                </div>
                            )}
                        </div>
                        <div class="modal-footer">
                            {status === 'uploading' ? (
                                <button class="btn btn-outline-secondary" onClick={this.handleCancel}>
                                    Cancel upload
                                </button>
                            ) : (
                                <button class="btn btn-primary" onClick={this.handleDismiss}>
                                    OK
                                </button>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    private static formatSize(bytes: number): string {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(2) + ' MB';
    }

    private static formatSpeed(bytesPerSecond: number): string {
        if (bytesPerSecond < 1024) return bytesPerSecond + ' B/s';
        if (bytesPerSecond < 1024 * 1024) return (bytesPerSecond / 1024).toFixed(1) + ' KB/s';
        return (bytesPerSecond / (1024 * 1024)).toFixed(2) + ' MB/s';
    }
}

// ==================== 主类 ====================
export class GoTTYXterm {
    // The HTMLElement that contains our terminal
    elem: HTMLElement;

    // The xtermjs.XTerm
    term: Terminal;

    resizeListener: () => void;
    viewportResizeListener: (() => void) | null = null;
    private fitRequestId: number | null = null;

    message: HTMLElement;
    messageTimeout: number;
    messageTimer!: NodeJS.Timeout;

    connectionCountElem: HTMLElement;
    clearHistoryBtn: HTMLElement;
    uploadBtn: HTMLElement;
    restartBtn: HTMLElement;
    fileInput: HTMLInputElement;
    terminalStateElem: HTMLElement | null = null;
    private apiIndicatorElem: HTMLElement | null = null;
    private showTerminalStateOverlay: boolean;

    onResizeHandler!: IDisposable;
    onDataHandler!: IDisposable;

    fitAddOn: FitAddon;
    zmodemAddon: ZModemAddon;
    toServer!: (data: string | Uint8Array) => void;
    encoder: TextEncoder;
    sendUploadFile?: (msg: string) => void;
    sendRestart?: () => void | Promise<void>;
    private uploadMaxMessageSize = 1024;

    // Drop overlay and upload modal
    private dropOverlay: DropOverlay | null = null;
    private uploadModalContainer: HTMLElement | null = null;
    private currentUploadTask: UploadTask | null = null;
    private uploadStartTime: number = 0;

    // 输出/输入回调列表，用于空闲提醒等功能（可解绑）
    private outputCallbacks: Set<() => void> = new Set();
    private inputCallbacks: Set<() => void> = new Set();
    private connectTime: number = 0;
    private selectionCallbacks: Set<() => void> = new Set();
    private uploadCallbacks: Set<(fileName: string, progress: number) => void> = new Set();
    private lastCopyNotificationText: string = "";
    private lastCopyNotificationAt: number = 0;
    altIsMeta: boolean = false;

    constructor(elem: HTMLElement, preferences: Record<string, unknown> = {}) {
        this.elem = elem;
        this.showTerminalStateOverlay =
            (typeof gotty_show_terminal_state !== 'undefined') ? !!gotty_show_terminal_state : false;
        this.encoder = new TextEncoder();
        this.term = new Terminal({
            allowProposedApi: true,
            customGlyphs: true,
            rescaleOverlappingGlyphs: true,
            theme: {
                background: 'rgb(40, 41, 53)'
            },
            scrollback: 500
        });

        const unicode11Addon = new Unicode11Addon();
        this.term.loadAddon(unicode11Addon);
        this.term.unicode.activeVersion = '11';

        // OSC 52: applications (e.g. Claude Code under mouse-tracking) ask the
        // host terminal to write text to the system clipboard. xterm.js has no
        // built-in handler for this, so the sequence would otherwise be dropped.
        // Format: OSC 52 ; Pc ; <base64 | "?" | ""> ST
        this.term.parser.registerOscHandler(52, (data) => {
            const sep = data.indexOf(';');
            if (sep < 0) return true;
            const payload = data.slice(sep + 1);
            // "?" is a clipboard-read request; "" clears the clipboard.
            // Ignore both — read-back leaks data, and we have no legitimate
            // need to clear the user's clipboard from the PTY.
            if (payload === '' || payload === '?') return true;

            let text: string;
            try {
                const bin = atob(payload);
                const bytes = new Uint8Array(bin.length);
                for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
                text = new TextDecoder('utf-8').decode(bytes);
            } catch {
                return true;
            }

            if (navigator.clipboard?.writeText) {
                navigator.clipboard.writeText(text).catch(() => {
                    this.fallbackCopyToClipboard(text);
                });
            } else {
                this.fallbackCopyToClipboard(text);
            }
            return true;
        });

        this.setPreferences(preferences);

        this.fitAddOn = new FitAddon();
        this.zmodemAddon = new ZModemAddon({
            toTerminal: (x: Uint8Array) => this.term.write(x),
            toServer: (x: Uint8Array) => this.sendInput(x)
        });
        this.term.loadAddon(new WebLinksAddon());
        this.term.loadAddon(this.fitAddOn);
        this.term.loadAddon(new ImageAddon());
        this.term.loadAddon(this.zmodemAddon);

        this.message = elem.ownerDocument.createElement("div");
        this.message.className = "xterm-overlay";
        this.messageTimeout = 2000;

        // 创建连接数显示
        this.connectionCountElem = elem.ownerDocument.createElement("div");
        this.connectionCountElem.className = "connection-count";
        this.connectionCountElem.title = "Connections";
        this.connectionCountElem.style.cssText = "position:fixed;top:10px;right:10px;min-width:52px;height:28px;background:rgba(0,0,0,0.7);color:#fff;padding:0 8px;border-radius:4px;font-size:12px;z-index:1000;display:flex;align-items:center;justify-content:center;gap:6px;box-sizing:border-box;";
        this.renderConnectionCount(1);
        elem.appendChild(this.connectionCountElem);

        // 创建清理历史按钮
        this.clearHistoryBtn = elem.ownerDocument.createElement("button");
        this.clearHistoryBtn.className = "clear-history-btn";
        this.clearHistoryBtn.innerHTML = '<svg width="14" height="14" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M2 5h12M5 5V3h6v2M7 7v6M9 7v6M4 5v9a1 1 0 001 1h6a1 1 0 001-1V5" stroke="rgba(255,255,255,0.7)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"/></svg>';
        this.clearHistoryBtn.title = "Clear history";
        this.clearHistoryBtn.style.cssText = "position:fixed;top:74px;right:10px;width:28px;height:28px;background:rgba(0,0,0,0.7);color:#fff;padding:0;border-radius:4px;font-size:12px;z-index:1000;cursor:pointer;border:none;display:flex;align-items:center;justify-content:center;";
        this.clearHistoryBtn.addEventListener('click', () => {
            this.clearHistory();
        });
        elem.appendChild(this.clearHistoryBtn);

        // 创建上传按钮
        this.uploadBtn = elem.ownerDocument.createElement("button");
        this.uploadBtn.className = "upload-btn";
        this.uploadBtn.innerHTML = '<svg width="14" height="14" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M8 11V3M8 3L5 6M8 3l3 3M3 13h10" stroke="rgba(255,255,255,0.7)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"/></svg>';
        this.uploadBtn.title = "Upload file";
        this.uploadBtn.style.cssText = "position:fixed;top:106px;right:10px;width:28px;height:28px;background:rgba(0,0,0,0.7);color:#fff;padding:0;border-radius:4px;font-size:12px;z-index:1000;cursor:pointer;border:none;display:flex;align-items:center;justify-content:center;";
        this.uploadBtn.addEventListener('click', () => {
            this.fileInput.click();
        });
        elem.appendChild(this.uploadBtn);

        // 创建重启按钮
        this.restartBtn = elem.ownerDocument.createElement("button");
        this.restartBtn.className = "restart-btn";
        this.restartBtn.innerHTML = '<svg width="14" height="14" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M13 6a5 5 0 10-1.46 3.54M13 6V2.5M13 6H9.5" stroke="rgba(255,255,255,0.7)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"/></svg>';
        this.restartBtn.title = "Restart";
        this.restartBtn.style.cssText = "position:fixed;top:138px;right:10px;width:28px;height:28px;background:rgba(0,0,0,0.7);color:#fff;padding:0;border-radius:4px;font-size:12px;z-index:1000;cursor:pointer;border:none;display:flex;align-items:center;justify-content:center;";
        this.restartBtn.addEventListener('click', () => {
            this.restartProcess();
        });
        elem.appendChild(this.restartBtn);

        // 创建隐藏的文件输入元素
        this.fileInput = elem.ownerDocument.createElement("input");
        this.fileInput.type = "file";
        this.fileInput.style.display = "none";
        this.fileInput.addEventListener('change', async (e) => {
            const files = (e.target as HTMLInputElement).files;
            if (files && files.length > 0) {
                await this.uploadFile(files[0]);
                this.fileInput.value = ''; // 清空选择，允许重复上传同一文件
            }
        });
        elem.appendChild(this.fileInput);

        if (this.showTerminalStateOverlay) {
            this.terminalStateElem = elem.ownerDocument.createElement("div");
            this.terminalStateElem.className = "terminal-state";
            this.terminalStateElem.style.cssText = "position:fixed;top:170px;right:10px;background:rgba(0,0,0,0.7);color:#fff;padding:4px 8px;border-radius:4px;font-size:11px;z-index:1000;";
            this.terminalStateElem.textContent = "Size policy: --";
            elem.appendChild(this.terminalStateElem);
        }

        // 创建上传模态框容器
        this.uploadModalContainer = document.createElement('div');
        document.body.appendChild(this.uploadModalContainer);

        // 创建 API 执行指示器（默认隐藏）
        this.apiIndicatorElem = elem.ownerDocument.createElement("div");
        this.apiIndicatorElem.className = "gotty-api-indicator";
        this.apiIndicatorElem.innerHTML = '<span class="api-indicator-dot"></span> API running';
        document.body.appendChild(this.apiIndicatorElem);

        // Auto-copy selection to clipboard
        this.term.onSelectionChange(() => {
            this.selectionCallbacks.forEach((cb) => cb());
            if (this.term.hasSelection()) {
                const text = this.term.getSelection();

                // Try modern Clipboard API first
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(text).then(() => {
                        this.showCopySuccessMessage(text);
                        // Keep focus on terminal after copying
                        this.term.focus();
                    }).catch(err => {
                        console.warn('Clipboard API failed, trying fallback:', err);
                        if (this.fallbackCopyToClipboard(text)) {
                            this.showCopySuccessMessage(text);
                        }
                    });
                } else {
                    // Fallback for non-secure contexts
                    if (this.fallbackCopyToClipboard(text)) {
                        this.showCopySuccessMessage(text);
                    }
                }
            } else {
                this.lastCopyNotificationText = "";
            }
        });

        // Set up drag & drop handler for file upload
        this.setupDragDropHandler();

        this.resizeListener = () => {
            this.scheduleFit();
        };

        this.term.open(elem);

        try {
            this.term.loadAddon(new WebglAddon());
        } catch (e) {
            console.warn("WebGL renderer failed to load, using canvas fallback", e);
        }

        this.fitTerminal();
        this.term.focus();

        // Pre-register the alt_is_meta handler; it's a no-op unless altIsMeta is true.
        this.setupAltIsMeta();

        window.addEventListener("resize", this.resizeListener);
        window.addEventListener("orientationchange", this.resizeListener);
        if (window.visualViewport) {
            this.viewportResizeListener = () => this.scheduleFit();
            window.visualViewport.addEventListener("resize", this.viewportResizeListener);
        }
    };

    // Set up drag & drop handler for file upload
    private setupDragDropHandler() {
        // 创建拖放遮罩
        this.dropOverlay = new DropOverlay();

        // Bind to window to ensure we capture all drag events
        // This prevents Chrome from opening dropped files
        const preventDefaultDrag = (e: Event) => {
            e.preventDefault();
            e.stopPropagation();
        };
        ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
            window.addEventListener(eventName, preventDefaultDrag, false);
        });

        // Show overlay on drag enter
        window.addEventListener('dragenter', (e: DragEvent) => {
            if (e.dataTransfer?.files.length) {
                this.dropOverlay?.show(e.dataTransfer.files);
                document.body.classList.add('gotty-drag-border');
            }
        }, false);

        // Update file list on drag over (throttled)
        let lastDragOver = 0;
        window.addEventListener('dragover', (e: DragEvent) => {
            const now = Date.now();
            if (e.dataTransfer?.files.length && now - lastDragOver > 100) {
                lastDragOver = now;
                this.dropOverlay?.show(e.dataTransfer.files);
            }
        }, false);

        // Remove overlay on drag leave
        window.addEventListener('dragleave', (e: DragEvent) => {
            // Only hide if leaving the window or dropping outside
            if (!e.relatedTarget || (
                typeof e.relatedTarget === 'object' &&
                !document.body.contains(e.relatedTarget as Node)
            )) {
                this.dropOverlay?.hide();
                document.body.classList.remove('gotty-drag-border');
            }
        }, false);

        // Handle dropped files
        window.addEventListener('drop', async (e: DragEvent) => {
            e.preventDefault();
            this.dropOverlay?.hide();
            document.body.classList.remove('gotty-drag-border');

            const files = e.dataTransfer?.files;
            if (files && files.length > 0) {
                // Notify input activity
                this.inputCallbacks.forEach((cb) => cb());

                // Upload all dropped files
                for (let i = 0; i < files.length; i++) {
                    const file = files[i];
                    await this.uploadFile(file);

                    // If multiple files, show separator
                    if (i < files.length - 1) {
                        await new Promise(resolve => setTimeout(resolve, 100));
                    }
                }
            }
        }, false);
    }

    // Upload file to server
    private async uploadFile(file: File): Promise<void> {
        const fileName = file.name;
        const fileSize = file.size;

        if (fileSize === 0) {
            this.showMessage(`${fileName} is empty`, 3000);
            return;
        }

        const chunkSize = this.getUploadChunkSize(fileName, fileSize);
        if (chunkSize <= 0) {
            this.showMessage(`Upload failed for ${fileName}: chunk too large`, 3000);
            return;
        }

        const totalChunks = Math.ceil(fileSize / chunkSize);

        // 创建上传任务状态
        const uploadTask: UploadTask = {
            id: Date.now().toString(36) + Math.random().toString(36).substr(2),
            name: fileName,
            size: fileSize,
            progress: 0,
            speed: 0,
            status: 'uploading',
            startTime: Date.now()
        };

        this.currentUploadTask = uploadTask;
        this.uploadStartTime = Date.now();

        // 显示上传进度模态框
        this.showUploadModal(uploadTask);

        // Notify upload start
        this.uploadCallbacks.forEach((cb) => cb(fileName, 0));
        this.showMessage(`Uploading ${fileName}...`, 0);

        try {
            const arrayBuffer = await file.arrayBuffer();
            const uint8Array = new Uint8Array(arrayBuffer);

            for (let chunk = 0; chunk < totalChunks; chunk++) {
                // 检查是否已取消
                if (this.currentUploadTask?.status === 'cancelled') {
                    this.showMessage(`Upload cancelled: ${fileName}`, 3000);
                    this.hideUploadModal();
                    return;
                }

                const start = chunk * chunkSize;
                const end = Math.min(start + chunkSize, fileSize);
                const chunkData = uint8Array.slice(start, end);

                // Convert to base64 using binary string conversion (avoids stack overflow for large chunks)
                let binary = '';
                for (let i = 0; i < chunkData.length; i++) {
                    binary += String.fromCharCode(chunkData[i]);
                }
                const base64Data = btoa(binary);

                // Create upload message
                const uploadMsg: UploadFileMessage = {
                    name: fileName,
                    size: fileSize,
                    chunk: chunk,
                    totalChunks: totalChunks,
                    data: base64Data
                };

                // Send to server
                if (this.sendUploadFile) {
                    this.sendUploadFile(MSG_UPLOAD_FILE + JSON.stringify(uploadMsg));
                }

                // Calculate progress and speed
                const progress = Math.round(((chunk + 1) / totalChunks) * 100);
                const now = Date.now();
                const elapsed = (now - this.uploadStartTime) / 1000;
                const uploadedBytes = (chunk + 1) * chunkSize;
                const speed = elapsed > 0 ? uploadedBytes / elapsed : 0;

                // 更新任务状态
                uploadTask.progress = progress;
                uploadTask.speed = speed;
                uploadTask.size = fileSize; // 确保使用原始大小

                // Notify progress
                this.uploadCallbacks.forEach((cb) => cb(fileName, progress));
            }

            // 上传完成 - 等待用户点击确定按钮关闭
            uploadTask.status = 'completed';
            uploadTask.progress = 100;
            this.showMessage(`${fileName} uploaded successfully`, 3000);
            // 不自动关闭模态框，等待用户点击确定按钮

        } catch (error) {
            console.error('Upload failed:', error);
            uploadTask.status = 'error';
            this.showMessage(`Upload failed for ${fileName}`, 3000);
        }
    }

    // 显示上传模态框
    private showUploadModal(task: UploadTask) {
        if (!this.uploadModalContainer) return;

        render(
            <UploadProgressModal
                task={task}
                onCancel={() => this.cancelUpload()}
                onDismiss={() => this.hideUploadModal()}
            />,
            this.uploadModalContainer
        );
    }

    // 隐藏上传模态框
    private hideUploadModal() {
        if (this.uploadModalContainer) {
            // 先调用模态框的 hide 方法，等待 Bootstrap 清理 backdrop
            const modalElem = this.uploadModalContainer.querySelector('.modal');
            if (modalElem) {
                const bsModal = Modal.getInstance(modalElem);
                if (bsModal) {
                    // 监听隐藏完成事件
                    const onHidden = () => {
                        this.uploadModalContainer!.innerHTML = '';
                        this.currentUploadTask = null;
                        modalElem.removeEventListener('hidden.bs.modal', onHidden);
                    };
                    modalElem.addEventListener('hidden.bs.modal', onHidden);
                    bsModal.hide();
                    return;
                }
            }
            // 如果没有找到模态框实例，直接清理
            this.uploadModalContainer.innerHTML = '';
        }
        this.currentUploadTask = null;
    }

    // 取消上传
    private cancelUpload() {
        if (this.currentUploadTask && this.currentUploadTask.status === 'uploading') {
            this.currentUploadTask.status = 'cancelled';

            // 发送取消消息到服务器
            if (this.sendUploadFile) {
                this.sendUploadFile(MSG_UPLOAD_CANCEL);
            }
        }
    }

    private scheduleFit(): void {
        if (this.fitRequestId !== null) {
            cancelAnimationFrame(this.fitRequestId);
        }
        this.fitRequestId = requestAnimationFrame(() => {
            this.fitRequestId = null;
            this.fitTerminal();
        });
    }

    private fitTerminal(): void {
        // Fit terminal size to the container so the viewport can reach the bottom.
        this.fitAddOn.fit();
        this.term.scrollToBottom();
    }

    info(): { columns: number, rows: number } {
        return { columns: this.term.cols, rows: this.term.rows };
    };

    // This gets called from the Websocket's onReceive handler
    output(data: Uint8Array) {
        this.zmodemAddon.consume(data);
        // 通知所有输出回调
        this.outputCallbacks.forEach((cb) => cb());
    };

    // 注册输出回调（返回解绑函数）
    onOutput(callback: () => void): () => void {
        this.outputCallbacks.add(callback);
        return () => {
            this.outputCallbacks.delete(callback);
        };
    }

    // 注册输入回调（返回解绑函数）
    onInputActivity(callback: () => void): () => void {
        this.inputCallbacks.add(callback);
        return () => {
            this.inputCallbacks.delete(callback);
        };
    }

    // 注册选择回调（返回解绑函数）
    onSelectionActivity(callback: () => void): () => void {
        this.selectionCallbacks.add(callback);
        return () => {
            this.selectionCallbacks.delete(callback);
        };
    }

    getMessage(): HTMLElement {
        return this.message;
    }

    showMessage(message: string, timeout: number) {
        this.message.innerHTML = message;
        this.showMessageElem(timeout);
    }

    showMessageElem(timeout: number) {
        this.elem.appendChild(this.message);

        if (this.messageTimer) {
            clearTimeout(this.messageTimer);
        }
        if (timeout > 0) {
            this.messageTimer = setTimeout(() => {
                try {
                    this.elem.removeChild(this.message);
                } catch (error) {
                    console.error(error);
                }
            }, timeout);
        }
    };

    removeMessage(): void {
        if (this.message.parentNode == this.elem) {
            this.elem.removeChild(this.message);
        }
    }

    setWindowTitle(title: string) {
        document.title = title;
    };

    setPreferences(value?: Record<string, unknown> | null) {
        if (!value) {
            return;
        }

        // Apply font settings first so the renderer initializes with the
        // correct font metrics before any renderer-specific logic.
        const keys = Object.keys(value);
        const fontKeys = keys.filter(k => k === "font-family" || k === "font-size");
        const otherKeys = keys.filter(k => k !== "font-family" && k !== "font-size");

        for (const key of [...fontKeys, ...otherKeys]) {
            switch (key) {
                case "font-family":
                    this.term.options.fontFamily = value[key] as string;
                    break;
                case "font-size":
                    this.term.options.fontSize = value[key] as number;
                    break;
                case "EnableWebGL":
                    // Already loaded by default in constructor — skip to avoid
                    // orphaning the first WebglAddon with a duplicate.
                    break;
                case "cursor-blink":
                    this.term.options.cursorBlink = value[key] as boolean;
                    break;
                case "cursor-style":
                    this.term.options.cursorStyle = value[key] as "block" | "underline" | "bar";
                    break;
                case "scrollback-lines":
                    this.term.options.scrollback = value[key] as number;
                    break;
                case "theme":
                    this.term.options.theme = value[key] as object;
                    break;
                case "alt-is-meta":
                    this.altIsMeta = value[key] as boolean;
                    break;
            }
        }
    };

    setupAltIsMeta() {
        this.term.attachCustomKeyEventHandler((event: KeyboardEvent) => {
            if (!this.altIsMeta) return true;

            // Only handle Alt+key without Ctrl/Meta
            if (!event.altKey || event.ctrlKey || event.metaKey) return true;

            // Skip special keys that should be handled by the browser
            // (Tab, arrows, function keys, etc.)
            if (event.code.startsWith('Alt') || event.code === 'Tab') return true;

            // Determine the character to send with the Escape prefix
            let char: string | null = null;

            if (event.code.startsWith('Key') && event.code.length === 4) {
                // Letter keys: use event.code to get the base character,
                // which works correctly on macOS where Option composes characters
                const letter = event.code[3];
                char = event.shiftKey ? letter : letter.toLowerCase();
            } else if (event.code.startsWith('Digit') && event.code.length === 6) {
                // Digit keys: handle unshifted digits and shifted symbols
                const digit = event.code[5];
                if (!event.shiftKey) {
                    char = digit;
                } else {
                    // Shifted digit keys produce symbols; use event.key
                    if (event.key.length === 1) {
                        char = event.key;
                    }
                }
            } else if (event.key === ' ') {
                // Alt+Space -> M-SPC
                char = ' ';
            } else if (event.key.length === 1 && event.key !== ' ') {
                // Other single-character keys (., /, ;, ', [, ], etc.)
                char = event.key;
            }

            if (char !== null) {
                event.preventDefault();
                this.toServer(this.encoder.encode('\x1b' + char));
                return false;
            }

            return true;
        });
    };

    private renderConnectionCount(count: number) {
        this.connectionCountElem.innerHTML = `<svg width="14" height="14" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M5.5 7.2a2.2 2.2 0 100-4.4 2.2 2.2 0 000 4.4zM10.5 7.2a2.2 2.2 0 100-4.4 2.2 2.2 0 000 4.4zM2.5 13.2c.3-2.1 1.6-3.4 3-3.4s2.7 1.3 3 3.4M7.5 12.4c.5-1.6 1.6-2.6 3-2.6 1.5 0 2.8 1.3 3 3.4" stroke="rgba(255,255,255,0.7)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"/></svg><span>${count}</span>`;
    };

    updateConnectionCount(count: number) {
        this.renderConnectionCount(count);
    };

    updateTerminalState(state: TerminalStatePayload) {
        if (!this.terminalStateElem) {
            return;
        }
        const leader = state.leaderClientId || "-";
        const size = `${state.activeCols}x${state.activeRows}`;
        this.terminalStateElem.textContent = `Size: ${size} | Policy: ${state.policy} | leader: ${leader}`;
    };

    showAPIIndicator(execId: string) {
        if (this.apiIndicatorElem) {
            this.apiIndicatorElem.setAttribute('data-exec-id', execId);
            this.apiIndicatorElem.classList.add('active');
        }
    };

    hideAPIIndicator(execId: string) {
        if (this.apiIndicatorElem) {
            const current = this.apiIndicatorElem.getAttribute('data-exec-id');
            if (current === execId) {
                this.apiIndicatorElem.classList.remove('active');
                this.apiIndicatorElem.removeAttribute('data-exec-id');
            }
        }
    };

    sendInput(data: Uint8Array) {
        return this.toServer(data)
    }

    onInput(callback: (input: string | Uint8Array) => void) {
        this.encoder = new TextEncoder()
        this.toServer = callback;

        // I *think* we're ok like this, but if not, we can dispose
        // of the previous handler and put the new one in place.
        if (this.onDataHandler !== undefined) {
            return
        }

        this.connectTime = Date.now();

        this.onDataHandler = this.term.onData((input) => {
            // During the first few seconds after connection, filter out
            // terminal query responses that xterm.js generates automatically.
            // The WebSocket round-trip latency causes these to arrive at the
            // PTY after the shell has moved on from its startup queries,
            // so they get echoed as visible garbled text.
            // After the startup window, let everything through so that
            // applications (vim, tmux, etc.) can query the terminal normally.
            if (Date.now() - this.connectTime < 3000) {
                const filtered = input.replace(
                    /\x1b(?:\[\?[0-9;]*c|\[>[0-9;]*c|\[[0-9;]*R|\]1[0-2];[^\x07\x1b]*(?:\x07|\x1b\\)|\[\?[0-9;]*\$y)/g,
                    ''
                );
                if (filtered.length === 0) {
                    return;
                }
                input = filtered;
            }
            this.inputCallbacks.forEach((cb) => cb());
            this.toServer(this.encoder.encode(input));
        });
    };

    // Set the upload file sender (called from WebTTY)
    setUploadFileSender(sender: (msg: string) => void) {
        this.sendUploadFile = sender;
    }

    setRestartSender(sender: () => void | Promise<void>) {
        this.sendRestart = sender;
    }

    setUploadFileBufferSize(size: number) {
        if (Number.isFinite(size) && size > 0) {
            this.uploadMaxMessageSize = size;
        }
    }

    private getUploadChunkSize(fileName: string, fileSize: number): number {
        const maxPayloadBytes = Math.max(0, this.uploadMaxMessageSize - 1);
        const maxValue = Math.max(1, fileSize);
        const overheadMessage: UploadFileMessage = {
            name: fileName,
            size: fileSize,
            chunk: maxValue - 1,
            totalChunks: maxValue,
            data: ""
        };
        const overheadBytes = this.encoder.encode(JSON.stringify(overheadMessage)).length;
        const available = maxPayloadBytes - overheadBytes;
        if (available < 4) {
            return 0;
        }
        const maxRaw = Math.floor(available / 4) * 3;
        return Math.min(PREFERRED_CHUNK_SIZE, maxRaw);
    }

    // Register upload callback (returns unsubscribe function)
    onUpload(callback: (fileName: string, progress: number) => void): () => void {
        this.uploadCallbacks.add(callback);
        return () => {
            this.uploadCallbacks.delete(callback);
        };
    }

    onResize(callback: (colmuns: number, rows: number) => void) {
        this.onResizeHandler = this.term.onResize(() => {
            callback(this.term.cols, this.term.rows);
        });
    };

    deactivate(): void {
        this.onDataHandler.dispose();
        this.onResizeHandler.dispose();
        this.term.blur();
    }

    reset(): void {
        this.removeMessage();
        this.term.clear();
        this.hideUploadModal();
    }

    clearHistory(): void {
        // Send clear command to server
        this.sendInput(this.encoder.encode("clear\n"));
        // Clear local terminal display
        this.term.clear();
        this.showMessage("History cleared", 2000);
    }

    restartProcess(): void {
        if (!this.sendRestart) {
            this.showMessage("Restart is not ready", 2000);
            return;
        }
        this.term.clear();
        this.showMessage("Restarting GoTTY server...", 0);
        void this.sendRestart();
    }

    close(): void {
        window.removeEventListener("resize", this.resizeListener);
        window.removeEventListener("orientationchange", this.resizeListener);
        if (window.visualViewport && this.viewportResizeListener) {
            window.visualViewport.removeEventListener("resize", this.viewportResizeListener);
        }
        if (this.fitRequestId !== null) {
            cancelAnimationFrame(this.fitRequestId);
            this.fitRequestId = null;
        }
        this.term.dispose();
        this.dropOverlay?.destroy();
        this.hideUploadModal();
        if (this.uploadModalContainer) {
            document.body.removeChild(this.uploadModalContainer);
        }
    }

    disableStdin(): void {
        this.term.options.disableStdin = true;
    }

    enableStdin(): void {
        this.term.options.disableStdin = false;
    }

    focus(): void {
        this.term.focus();
    }

    private showCopySuccessMessage(text: string): void {
        if (!text || text === this.lastCopyNotificationText) {
            return;
        }

        const now = Date.now();
        if (now - this.lastCopyNotificationAt < COPY_SUCCESS_MIN_INTERVAL_MS) {
            return;
        }

        this.lastCopyNotificationText = text;
        this.lastCopyNotificationAt = now;
        this.showMessage(COPY_SUCCESS_MESSAGE, COPY_SUCCESS_TIMEOUT_MS);
    }

    fallbackCopyToClipboard(text: string): boolean {
        const textarea = document.createElement('textarea');
        textarea.value = text;
        textarea.style.position = 'fixed';
        textarea.style.opacity = '0';
        document.body.appendChild(textarea);
        textarea.select();

        let copied = false;
        try {
            copied = document.execCommand('copy');
        } catch (err) {
            console.warn('Fallback copy failed:', err);
        }

        document.body.removeChild(textarea);

        // Restore focus to terminal
        this.term.focus();
        return copied;
    }
}

export { GoTTYXterm as OurXterm };
